297	  /**
298	   * Update an existing issue.
299	   */
300	  async update(id: IssueId, params: UpdateParams): Promise<UpdateResult> {
301	    const trackerDir = resolveTrackerDir(this.cwd);
302	    if (!trackerDir) {
303	      throw new TrackgenticError(
304	        ErrorCodes.NOT_INITIALIZED.result,
305	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
306	        ErrorCodes.NOT_INITIALIZED.exitCode,
307	      );
308	    }
309	
310	    // Validate at least one field provided (besides author)
311	    const hasField =
312	      params.title !== undefined ||
313	      params.description !== undefined ||
314	      params.status !== undefined ||
315	      params.assignee !== undefined ||
316	      params.tags !== undefined ||
317	      params.priority !== undefined ||
318	      params.parentId !== undefined;
319	
320	    if (!hasField) {
321	      throw new TrackgenticError(
322	        ErrorCodes.INVALID_PARAMS.result,
323	        "At least one field must be provided for update.",
324	        ErrorCodes.INVALID_PARAMS.exitCode,
325	      );
326	    }
327	
328	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
329	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
330	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
331	    if (authResult instanceof TrackgenticError) return authResult;
332	    const author = authResult.author;
333	
334	    const index = await readIndex(trackerDir);
335	    const entry = findEntry(index, id);
336	    if (!entry) {
337	      throw new TrackgenticError(
338	        ErrorCodes.NOT_FOUND.result,
339	        `Issue ${id} not found in index.`,
340	        ErrorCodes.NOT_FOUND.exitCode,
341	      );
342	    }
343	
344	    const issueFilePath = join(trackerDir, entry.path);
345	    if (!existsSync(issueFilePath)) {
346	      throw new TrackgenticError(
347	        ErrorCodes.ISSUE_MISSING.result,
348	        `Issue file for ${id} is missing.`,
349	        ErrorCodes.ISSUE_MISSING.exitCode,
350	      );
351	    }
352	
353	    // Build update event content with only the provided fields
354	    const content: Partial<
355	      Pick<
356	        IssueProperties,
357	        "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
358	      >
359	    > = {};
360	    if (params.title !== undefined) content.title = params.title;
361	    if (params.description !== undefined) content.description = params.description;
362	    if (params.status !== undefined) content.status = params.status;
363	    if (params.assignee !== undefined) content.assignee = params.assignee;
364	    if (params.tags !== undefined) content.tags = params.tags;
365	    if (params.priority !== undefined) content.priority = params.priority;
366	    if (params.parentId !== undefined) content.parentId = params.parentId;
367	
368	    const now = new Date().toISOString();
369	
370	    const updateEvent = {
371	      type: "update" as const,
372	      timestamp: now,
373	      author,
374	      content,
375	    };
376	
377	    // Append event to issue file
378	    await appendEvent(issueFilePath, updateEvent);
379	
380	    // Recompute state from all events
381	    const events = await replayEvents(issueFilePath);
382	    const computed = computeState(events, id);
383	
384	    // Update index entry with new computed values
385	    const updatedIndex = updateEntry(index, id, {
386	      title: computed.title,
387	      status: computed.status,
388	      assignee: computed.assignee,
389	      parentId: computed.parentId,
390	      tags: computed.tags,
391	      priority: computed.priority,
392	    });
393	
394	    await writeIndex(trackerDir, updatedIndex);
395	
396	    return { result: "OK" };
397	  }
