1	import { join } from "node:path";
2	import type { IndexEntry, IndexFile, IssueId } from "../types";
3	import { atomicWriteJSON, readJSON } from "./file-io";
4	
5	const INDEX_FILE = "index.json";
6	
7	/**
8	 * Read the index file from the tracker directory.
9	 */
10	export async function readIndex(trackerDir: string): Promise<IndexFile> {
11	  return readJSON<IndexFile>(join(trackerDir, INDEX_FILE));
12	}
13	
14	/**
15	 * Write the index file to the tracker directory atomically.
16	 */
17	export async function writeIndex(trackerDir: string, index: IndexFile): Promise<void> {
18	  await atomicWriteJSON(join(trackerDir, INDEX_FILE), index);
19	}
20	
21	/**
22	 * Binary search for an entry by id in a sorted array.
23	 * Returns the index of the entry, or -1 if not found.
24	 */
25	function binarySearchIndex(entries: IndexEntry[], id: IssueId): number {
26	  let lo = 0;
27	  let hi = entries.length - 1;
28	
29	  while (lo <= hi) {
30	    const mid = (lo + hi) >>> 1;
31	    const midEntry = entries[mid];
32	    if (!midEntry) break; // Safety check for noUncheckedIndexedAccess
33	    const cmp = midEntry.id.localeCompare(id);
34	    if (cmp === 0) return mid;
35	    if (cmp < 0) lo = mid + 1;
36	    else hi = mid - 1;
37	  }
38	
39	  return -1;
40	}
41	
42	/**
43	 * Insert entry into the correct array (open or closed) maintaining sort by id.
44	 * Returns a new IndexFile (immutable — original is not mutated).
45	 */
46	export function insertEntry(index: IndexFile, entry: IndexEntry): IndexFile {
47	  const isOpen = entry.status !== "closed";
48	  const arr = isOpen ? index.open : index.closed;
49	
50	  // Find insertion point via binary search
51	  let lo = 0;
52	  let hi = arr.length;
53	  while (lo < hi) {
54	    const mid = (lo + hi) >>> 1;
55	    const midEntry = arr[mid];
56	    if (midEntry && midEntry.id.localeCompare(entry.id) < 0) {
57	      lo = mid + 1;
58	    } else {
59	      hi = mid;
60	    }
61	  }
62	
63	  const newArr = [...arr.slice(0, lo), entry, ...arr.slice(lo)];
64	
65	  // Update childrenOf if entry has a parentId
66	  const childrenOf = { ...index.childrenOf };
67	  if (entry.parentId) {
68	    const existing = childrenOf[entry.parentId] ?? [];
69	    childrenOf[entry.parentId] = [...existing, entry.id];
70	  }
71	
72	  return isOpen ? { ...index, open: newArr, childrenOf } : { ...index, closed: newArr, childrenOf };
73	}
74	
75	/**
76	 * Update an existing entry (find by id, replace).
77	 * Handles open <-> closed array moves if status changed.
78	 * Returns a new IndexFile (immutable — original is not mutated).
79	 */
80	export function updateEntry(
81	  index: IndexFile,
82	  id: IssueId,
83	  updates: Partial<IndexEntry>,
84	): IndexFile {
85	  // Try to find in open array
86	  const openIdx = binarySearchIndex(index.open, id);
87	  if (openIdx !== -1) {
88	    const oldEntry = index.open[openIdx];
89	    if (!oldEntry) return index;
90	    const newEntry: IndexEntry = { ...oldEntry, ...updates };
91	
92	    // If status changed to closed, move to closed array
93	    if (newEntry.status === "closed") {
94	      const newOpen = [...index.open.slice(0, openIdx), ...index.open.slice(openIdx + 1)];
95	      return insertEntry({ ...index, open: newOpen }, newEntry);
96	    }
97	
98	    // Stay in open — update in place
99	    const newOpen = [...index.open];
100	    newOpen[openIdx] = newEntry;
101	    return { ...index, open: newOpen };
102	  }
103	
104	  // Try to find in closed array
105	  const closedIdx = binarySearchIndex(index.closed, id);
106	  if (closedIdx !== -1) {
107	    const oldEntry = index.closed[closedIdx];
108	    if (!oldEntry) return index;
109	    const newEntry: IndexEntry = { ...oldEntry, ...updates };
110	
111	    // If status changed from closed to open, move to open array
112	    if (newEntry.status !== "closed") {
113	      const newClosed = [...index.closed.slice(0, closedIdx), ...index.closed.slice(closedIdx + 1)];
114	      return insertEntry({ ...index, closed: newClosed }, newEntry);
115	    }
116	
117	    // Stay in closed — update in place
118	    const newClosed = [...index.closed];
119	    newClosed[closedIdx] = newEntry;
120	    return { ...index, closed: newClosed };
121	  }
122	
123	  // Entry not found — return unchanged
124	  return index;
125	}
126	
127	/**
128	 * Binary search by id in both open and closed arrays.
129	 * Returns null if not found.
130	 */
131	export function findEntry(index: IndexFile, id: IssueId): IndexEntry | null {
132	  const openIdx = binarySearchIndex(index.open, id);
133	  if (openIdx !== -1) return index.open[openIdx] ?? null;
134	
135	  const closedIdx = binarySearchIndex(index.closed, id);
136	  if (closedIdx !== -1) return index.closed[closedIdx] ?? null;
137	
138	  return null;
139	}
140	
141	/**
142	 * Remove entry from whichever array it's in.
143	 * Returns unchanged index if not found.
144	 * Returns a new IndexFile (immutable — original is not mutated).
145	 */
146	export function removeEntry(index: IndexFile, id: IssueId): IndexFile {
147	  const openIdx = binarySearchIndex(index.open, id);
148	  if (openIdx !== -1) {
149	    return { ...index, open: [...index.open.slice(0, openIdx), ...index.open.slice(openIdx + 1)] };
150	  }
151	
152	  const closedIdx = binarySearchIndex(index.closed, id);
153	  if (closedIdx !== -1) {
154	    return {
155	      ...index,
156	      closed: [...index.closed.slice(0, closedIdx), ...index.closed.slice(closedIdx + 1)],
157	    };
158	  }
159	
160	  return index;
161	}
