1	import type { ConfigFile, UsersFile } from "../types";
2	import { ErrorCodes, TrackgenticError } from "./errors";
3	
4	/**
5	 * Resolve the author for an operation based on auth configuration.
6	 *
7	 * Synchronous — only does in-memory lookups.
8	 * Reads TRACKGENTIC_USER_TOKEN from env if no explicit token is provided.
9	 */
10	export function resolveAuthor(options: {
11	  token?: string;
12	  config: ConfigFile;
13	  users: UsersFile;
14	  requiresWrite: boolean;
15	}): { author: string } | TrackgenticError {
16	  const { config, users, requiresWrite } = options;
17	  // biome-ignore lint/complexity/useLiteralKeys: noPropertyAccessFromIndexSignature requires bracket notation
18	  const token = options.token ?? process.env["TRACKGENTIC_USER_TOKEN"];
19	
20	  // If token is provided, validate it regardless of mode
21	  if (token) {
22	    const user = users.users.find((u) => u.token === token);
23	    if (!user) {
24	      return new TrackgenticError(
25	        ErrorCodes.INVALID_TOKEN.result,
26	        "Invalid authentication token.",
27	        ErrorCodes.INVALID_TOKEN.exitCode,
28	      );
29	    }
30	    return { author: user.name };
31	  }
32	
33	  // No token provided — check mode
34	  switch (config.auth.mode) {
35	    case "strict":
36	      return new TrackgenticError(
37	        ErrorCodes.TOKEN_REQUIRED.result,
38	        "Authentication required. Set TRACKGENTIC_USER_TOKEN environment variable.",
39	        ErrorCodes.TOKEN_REQUIRED.exitCode,
40	      );
41	
42	    case "read-only":
43	      if (requiresWrite) {
44	        return new TrackgenticError(
45	          ErrorCodes.TOKEN_REQUIRED.result,
46	          "Authentication required for write operations. Set TRACKGENTIC_USER_TOKEN environment variable.",
47	          ErrorCodes.TOKEN_REQUIRED.exitCode,
48	        );
49	      }
50	      // Read operation — fall through to use default user
51	      break;
52	
53	    case "open":
54	      // No token needed — fall through to use default user
55	      break;
56	  }
57	
58	  // Use default user for unauthenticated access
59	  const defaultUser = config.auth.defaultUser;
60	  if (!defaultUser) {
61	    return new TrackgenticError(
62	      ErrorCodes.DEFAULT_USER_MISSING.result,
63	      "No default user configured.",
64	      ErrorCodes.DEFAULT_USER_MISSING.exitCode,
65	    );
66	  }
67	
68	  return { author: defaultUser };
69	}
